package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", "\\N",
                new Object[]{"Header comment"}, new String[]{"Header1", "Header2"}, false, true, false, true, false);
    }

    @Test
    public void testGetQuoteMode() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;

        // When
        QuoteMode actualQuoteMode = csvFormat.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }

    @Test
    public void testDefaultCSVFormat() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;

        // When
        QuoteMode actualQuoteMode = CSVFormat.DEFAULT.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }

    @Test
    public void testExcelCSVFormat() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;

        // When
        QuoteMode actualQuoteMode = CSVFormat.EXCEL.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }

    @Test
    public void testInformixUnloadCSVFormat() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;

        // When
        QuoteMode actualQuoteMode = CSVFormat.INFORMIX_UNLOAD_CSV.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }

    @Test
    public void testInformixUnloadCSVFormatWithMock() {
        // Given
        QuoteMode expectedQuoteMode = QuoteMode.ALL;
        CSVFormat mockFormat = mock(CSVFormat.class);
        when(mockFormat.getQuoteMode()).thenReturn(QuoteMode.ALL);

        // When
        QuoteMode actualQuoteMode = mockFormat.getQuoteMode();

        // Then
        assertEquals(expectedQuoteMode, actualQuoteMode);
    }
}
